use crate::api::*;
use crate::distance::l2_distance;
use std::sync::RwLock;
use std::collections::HashMap;

pub struct VectorDB {
    // Store vectors in a HashMap protected by RwLock for thread-safe access
    vectors: RwLock<HashMap<u64, Vec<f32>>>,
}

impl VectorDB {
    pub fn new() -> Self {
        VectorDB {
            vectors: RwLock::new(HashMap::new()),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        let mut vectors = self.vectors.write().unwrap();
        vectors.insert(id, vector);
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let mut db_vectors = self.vectors.write().unwrap();
        let count = vectors.len();
        for (id, vector) in vectors {
            db_vectors.insert(id, vector);
        }
        count
    }

    pub fn search(&self, query: &[f32], top_k: u32) -> Vec<SearchResult> {
        let vectors = self.vectors.read().unwrap();

        // Brute-force: compute distance to all vectors
        let mut results: Vec<SearchResult> = vectors
            .iter()
            .map(|(id, vec)| SearchResult {
                id: *id,
                distance: l2_distance(query, vec),
            })
            .collect();

        // Sort by distance ascending
        results.sort_by(|a, b| a.distance.partial_cmp(&b.distance).unwrap());

        // Return top-k
        results.truncate(top_k as usize);
        results
    }
}

