        let n = self.len();
        if n < NUM_CENTROIDS * 10 {
            // Not enough data to build index
            return;
        }

        // Initialize centroids using k-means++ initialization
        self.centroids = Vec::with_capacity(NUM_CENTROIDS);

        // First centroid is random
        let mut rng_state = 12345u64;
        let first_idx = (self.fast_rand(&mut rng_state) % n as u64) as usize;
        self.centroids.push(self.get_vector(first_idx).to_vec());

        // Select remaining centroids using k-means++ (simplified)
        for _ in 1..NUM_CENTROIDS {
            let mut max_dist = 0.0f64;
            let mut best_idx = 0;

            // Sample a subset for speed
            let sample_size = (n / 10).max(1000);
            for _ in 0..sample_size {
                let idx = (self.fast_rand(&mut rng_state) % n as u64) as usize;
                let vec = self.get_vector(idx);

                // Find distance to nearest centroid
                let mut min_dist = f64::MAX;
                for centroid in &self.centroids {
                    let dist = l2_distance(vec, centroid);
                    if dist < min_dist {
                        min_dist = dist;
                    }
                }

                if min_dist > max_dist {
                    max_dist = min_dist;
                    best_idx = idx;
                }
            }

            self.centroids.push(self.get_vector(best_idx).to_vec());
        }

